"use client";

import { useEffect, useMemo, useRef, useState, type PointerEvent as ReactPointerEvent } from "react";

const API = process.env.NEXT_PUBLIC_API_URL || "https://flyway-api.zileslabs.com";
type LiveReport = { id:string; species:string; flock_size:string; behavior:string; zone_latitude:number; zone_longitude:number; confidence:number; occurred_at:string; confirmations:number; notes?:string|null;weather?:Record<string,any>|null;observed_weather?:Record<string,any>|null;reporter_name?:string };
type SightingComment = { id:string; body:string; display_name:string; created_at:string };
type MapReport = LiveReport & { x:number; y:number; size:number; color:string; age:string };
type Panel = "map" | "activity" | "saved" | "more" | "admin";
type Filter = string;
type CatalogSpecies = {slug:string;display_name:string;category_slug:string;enabled?:boolean};
type CatalogCategory = {slug:string;display_name:string};
type MapCenter = { lat:number; lon:number };
type Preferences = { visible_groups:string[]; default_days:number; start_view:"us"|"world"|"my_area"; auto_open_card:boolean };
type HeatCell = {cell_latitude:number;cell_longitude:number;report_count:number;dominant_category:string;intensity:number};

const labels: Record<string,string> = { mallard:"Mallard",teal:"Teal",gadwall:"Gadwall",pintail:"Pintail",wood_duck:"Wood duck",diver:"Diving duck",mixed:"Mixed ducks",other:"Other migratory bird",canada_goose:"Canada goose",snow_goose:"Snow goose",white_fronted_goose:"White-fronted goose",sandhill_crane:"Sandhill crane",tundra_swan:"Tundra swan",feeding:"Feeding",circling:"Circling",flying_over:"Flying over",resting:"Resting on water",moving_in:"Moving into area" };
const colors: Record<string,string> = { mallard:"green",teal:"blue",mixed:"gold",gadwall:"gray",canada_goose:"gold",snow_goose:"blue",white_fronted_goose:"gold",sandhill_crane:"gray",tundra_swan:"blue" };
const speciesValues: Record<string,string> = { Mallard:"mallard",Teal:"teal",Gadwall:"gadwall",Pintail:"pintail","Mixed ducks":"mixed","Canada goose":"canada_goose","Snow goose":"snow_goose","White-fronted goose":"white_fronted_goose","Sandhill crane":"sandhill_crane","Tundra swan":"tundra_swan" };
const geese=new Set(["canada_goose","snow_goose","white_fronted_goose","tundra_swan"]);
const allGroups=["ducks","geese","cranes","doves","shorebirds","upland","other"];
const defaultPreferences:Preferences={visible_groups:allGroups,default_days:7,start_view:"us",auto_open_card:true};
function birdGroup(species:string){return species==="sandhill_crane"?"cranes":geese.has(species)?"geese":"ducks";}
const amountValues: Record<string,string> = { "1–10":"1-10","10–25":"10-25","25–50":"25-50","50+":"50+" };

function age(iso:string){ const m=Math.max(1,Math.floor((Date.now()-new Date(iso).getTime())/60000)); return m<60?`${m}m`:`${Math.floor(m/60)}h`; }
function position(n:number, offset:number){ const value=Math.abs(Math.sin(n*997+offset)*10000); return 14+(value-Math.floor(value))*72; }
function project(lat:number,lon:number,zoom:number){const size=256*2**zoom;const safeLat=Math.max(-85.0511,Math.min(85.0511,lat));const sin=Math.sin(safeLat*Math.PI/180);return{x:(lon+180)/360*size,y:(.5-Math.log((1+sin)/(1-sin))/(4*Math.PI))*size};}
function unproject(x:number,y:number,zoom:number):MapCenter{const size=256*2**zoom;const lon=x/size*360-180;const n=Math.PI-2*Math.PI*y/size;return{lat:180/Math.PI*Math.atan(Math.sinh(n)),lon:((lon+540)%360)-180};}
async function request(path:string, options:RequestInit={}){ const res=await fetch(`${API}${path}`,options); const text=await res.text(); const data=text?JSON.parse(text):null; if(!res.ok) throw new Error(data?.error||"Request failed"); return data; }
function qrSource(value:unknown){const text=String(value||"").trim();if(!text)return"";if(text.startsWith("data:image/")||/^https:\/\//i.test(text))return text;if(text.startsWith("<svg")||text.startsWith("<?xml"))return`data:image/svg+xml;charset=utf-8,${encodeURIComponent(text)}`;return""}
async function compressImage(file:File){if(!file.type.startsWith("image/")||file.size<900000)return file;const bitmap=await createImageBitmap(file);const scale=Math.min(1,1800/Math.max(bitmap.width,bitmap.height));const canvas=document.createElement("canvas");canvas.width=Math.round(bitmap.width*scale);canvas.height=Math.round(bitmap.height*scale);canvas.getContext("2d")!.drawImage(bitmap,0,0,canvas.width,canvas.height);const blob=await new Promise<Blob|null>(resolve=>canvas.toBlob(resolve,"image/jpeg",.84));bitmap.close();return blob?new File([blob],file.name.replace(/\.[^.]+$/,"")+".jpg",{type:"image/jpeg"}):file}

export default function Home(){
  const [reports,setReports]=useState<MapReport[]>([]);
  const [selectedId,setSelectedId]=useState("");
  const [loading,setLoading]=useState(true);
  const [panel,setPanel]=useState<Panel>("map");
  const [filter,setFilter]=useState<Filter>("all");
  const [catalog,setCatalog]=useState<CatalogSpecies[]>([]); const [categories,setCategories]=useState<CatalogCategory[]>([]);
  const [timeDays,setTimeDays]=useState(7);
  const [savedIds,setSavedIds]=useState<string[]>([]);
  const [detailId,setDetailId]=useState("");
  const [cardOpen,setCardOpen]=useState(true);
  const [preferences,setPreferences]=useState<Preferences>(defaultPreferences);
  const [preferencesStatus,setPreferencesStatus]=useState("");
  const [zoom,setZoom]=useState(4);
  const [center,setCenter]=useState<MapCenter>({lat:39.5,lon:-98.35});
  const [viewport,setViewport]=useState({width:1280,height:720});
  const drag=useRef<{pointerX:number;pointerY:number;centerX:number;centerY:number}|null>(null);
  const pointers=useRef(new Map<number,{x:number;y:number}>());
  const pinch=useRef<{distance:number;zoom:number;worldX:number;worldY:number}|null>(null);
  const mapGesture=useRef(false);
  const pendingReportTap=useRef<{id:string;x:number;y:number;pointerId:number}|null>(null);
  const mapRef=useRef<HTMLDivElement|null>(null);
  const [reporting,setReporting]=useState(false);
  const [authOpen,setAuthOpen]=useState(false);
  const [authMode,setAuthMode]=useState<"login"|"signup"|"recover">("login");
  const [email,setEmail]=useState(""); const [password,setPassword]=useState(""); const [displayName,setDisplayName]=useState(""); const [authError,setAuthError]=useState("");const[authBusy,setAuthBusy]=useState(false);
  const [token,setToken]=useState(""); const [profile,setProfile]=useState<any>(null);
  const [species,setSpecies]=useState("mallard"); const [amount,setAmount]=useState("25–50"); const [behavior,setBehavior]=useState("feeding"); const [status,setStatus]=useState("");
  const [notes,setNotes]=useState(""); const [photo,setPhoto]=useState<File|null>(null);const [observedWeather,setObservedWeather]=useState<any>({sky:"",precipitation:"none",wind:"",wind_direction:"",temperature:"",temperature_unit:"F",visibility:""});
  const [photos,setPhotos]=useState<{id:string;url:string}[]>([]); const [comments,setComments]=useState<SightingComment[]>([]); const [comment,setComment]=useState(""); const [commentStatus,setCommentStatus]=useState("");
  const [heatCells,setHeatCells]=useState<HeatCell[]>([]);const [securityOpen,setSecurityOpen]=useState(false);const [newPassword,setNewPassword]=useState("");const [securityStatus,setSecurityStatus]=useState("");const [mfa,setMfa]=useState<any>(null);const [mfaEnroll,setMfaEnroll]=useState<any>(null);const [mfaCode,setMfaCode]=useState("");
  const [profileOpen,setProfileOpen]=useState(false);const [profileDraft,setProfileDraft]=useState<any>({});const [sessions,setSessions]=useState<any[]>([]);const [notificationsOpen,setNotificationsOpen]=useState(false);const [notifications,setNotifications]=useState<any[]>([]);const [layersOpen,setLayersOpen]=useState(false);const [showFlyways,setShowFlyways]=useState(false);
  const [confirmationState,setConfirmationState]=useState<{confirmed:boolean;own_report:boolean;loading:boolean;error?:string}>({confirmed:false,own_report:false,loading:false});

  const categoryFor=(slug:string)=>catalog.find(item=>item.slug===slug)?.category_slug||birdGroup(slug);
  const displayLabel=(slug:string)=>catalog.find(item=>item.slug===slug)?.display_name||labels[slug]||slug.replaceAll("_"," ");
  const visibleReports=useMemo(()=>reports.filter(r=>preferences.visible_groups.includes(categoryFor(r.species))&&(filter==="all"||filter===categoryFor(r.species))),[reports,filter,preferences.visible_groups,catalog]);
  const savedReports=useMemo(()=>reports.filter(r=>savedIds.includes(r.id)),[reports,savedIds]);
  const selected=useMemo(()=>reports.find(r=>r.id===selectedId)||visibleReports[0],[reports,visibleReports,selectedId]);
  const detail=useMemo(()=>reports.find(r=>r.id===detailId),[reports,detailId]);
  const mapGeometry=useMemo(()=>{const centerPx=project(center.lat,center.lon,zoom);const size=256*2**zoom;const tileZoom=Math.floor(zoom);const scale=2**(zoom-tileZoom);const tileCenter=project(center.lat,center.lon,tileZoom);const minX=Math.floor((tileCenter.x-viewport.width/(2*scale))/256)-1,maxX=Math.floor((tileCenter.x+viewport.width/(2*scale))/256)+1,minY=Math.max(0,Math.floor((tileCenter.y-viewport.height/(2*scale))/256)-1),maxY=Math.min(2**tileZoom-1,Math.floor((tileCenter.y+viewport.height/(2*scale))/256)+1);const tiles=[];for(let y=minY;y<=maxY;y++)for(let x=minX;x<=maxX;x++){const wrapped=((x%(2**tileZoom))+2**tileZoom)%(2**tileZoom);tiles.push({key:`${tileZoom}-${x}-${y}`,url:`https://tile.openstreetmap.org/${tileZoom}/${wrapped}/${y}.png`,left:(x*256-tileCenter.x)*scale+viewport.width/2,top:(y*256-tileCenter.y)*scale+viewport.height/2,tileSize:256*scale});}return{tiles,centerPx,size};},[center,zoom,viewport]);
  const clusters=useMemo(()=>{if(zoom>7)return[];const grouped=new Map<string,{x:number;y:number;reports:MapReport[]}>();visibleReports.forEach(r=>{const point=project(r.zone_latitude,r.zone_longitude,zoom);let dx=point.x-mapGeometry.centerPx.x;if(dx>mapGeometry.size/2)dx-=mapGeometry.size;if(dx<-mapGeometry.size/2)dx+=mapGeometry.size;const left=dx+viewport.width/2,top=point.y-mapGeometry.centerPx.y+viewport.height/2;const key=`${Math.round(left/90)}:${Math.round(top/90)}`;const g=grouped.get(key)||{x:0,y:0,reports:[]};g.x+=left;g.y+=top;g.reports.push(r);grouped.set(key,g)});return[...grouped.values()].map(g=>({...g,x:g.x/g.reports.length,y:g.y/g.reports.length}));},[visibleReports,zoom,mapGeometry,viewport]);

  async function load(){ try{ const data=await request(`/api/sightings?days=${timeDays}&limit=250`); const mapped=(data.sightings||[]).map((r:LiveReport)=>({...r,x:position(r.zone_latitude,1),y:position(r.zone_longitude,2),size:r.flock_size==="50+"?108:r.flock_size==="25-50"?92:68,color:colors[r.species]||"gray",age:age(r.occurred_at)})); setReports(mapped); if(mapped[0]) setSelectedId(v=>v||mapped[0].id); } finally{setLoading(false);} }
  useEffect(()=>{ const resize=()=>setViewport({width:window.innerWidth,height:window.innerHeight});resize();window.addEventListener("resize",resize);setSavedIds(JSON.parse(localStorage.getItem("flyway_saved")||"[]")); const saved=localStorage.getItem("flyway_session"); if(saved){ const s=JSON.parse(saved); setToken(s.access_token); request("/api/profile",{headers:{Authorization:`Bearer ${s.access_token}`}}).then(p=>{setProfile(p);applyPreferences(p.preferences||defaultPreferences);}).catch(()=>localStorage.removeItem("flyway_session")); } return()=>window.removeEventListener("resize",resize); },[]);
  useEffect(()=>{setLoading(true);load();},[timeDays]);
  useEffect(()=>{request("/api/catalog").then(data=>{setCatalog(data.species||[]);setCategories(data.categories||[]);}).catch(()=>{});},[]);
  useEffect(()=>{if(zoom>5){setHeatCells([]);return}request(`/api/map/heatmap?days=${timeDays}`).then(data=>setHeatCells(data.cells||[])).catch(()=>setHeatCells([]));},[zoom<=5,timeDays]);
  useEffect(()=>{if(!detailId)return;Promise.all([request(`/api/sightings/${detailId}/photos`),request(`/api/sightings/${detailId}/comments`)]).then(([p,c])=>{setPhotos(p.photos||[]);setComments(c.comments||[]);}).catch(()=>{setPhotos([]);setComments([]);});},[detailId]);
  useEffect(()=>{if(!selectedId||!token){setConfirmationState({confirmed:false,own_report:false,loading:false});return}setConfirmationState(s=>({...s,loading:true,error:undefined}));request(`/api/sightings/${selectedId}/confirmation-state`,{headers:{Authorization:`Bearer ${token}`}}).then(s=>setConfirmationState({...s,loading:false})).catch(e=>setConfirmationState({confirmed:false,own_report:false,loading:false,error:e instanceof Error?e.message:"Could not load confirmation"}))},[selectedId,token]);
  useEffect(()=>{document.querySelectorAll<HTMLButtonElement>(".confirm-btn").forEach(button=>{button.disabled=confirmationState.confirmed||confirmationState.own_report||confirmationState.loading;button.textContent=confirmationState.loading?"Checking…":confirmationState.confirmed?"✓ Confirmed":confirmationState.own_report?"Your report":"✓ Confirm activity";button.title=confirmationState.error||""})},[confirmationState,detailId,cardOpen]);
  useEffect(()=>{const element=mapRef.current;if(!element||panel!=="map")return;const wheel=(event:WheelEvent)=>{event.preventDefault();const next=Math.min(15,Math.max(2,zoom-event.deltaY*.002));if(next===zoom)return;const rect=element.getBoundingClientRect(),offsetX=event.clientX-rect.left-viewport.width/2,offsetY=event.clientY-rect.top-viewport.height/2,currentCenter=project(center.lat,center.lon,zoom),ratio=2**(next-zoom);setZoom(next);setCenter(unproject((currentCenter.x+offsetX)*ratio-offsetX,(currentCenter.y+offsetY)*ratio-offsetY,next))};element.addEventListener("wheel",wheel,{passive:false});return()=>element.removeEventListener("wheel",wheel)},[panel,zoom,center,viewport]);
  useEffect(()=>{const close=(event:KeyboardEvent)=>{if(event.key!=="Escape")return;if(authOpen)setAuthOpen(false);else if(reporting)setReporting(false);else if(detailId)setDetailId("");else if(panel!=="map")setPanel("map");else if(cardOpen)setCardOpen(false);};window.addEventListener("keydown",close);return()=>window.removeEventListener("keydown",close);},[authOpen,reporting,detailId,panel,cardOpen]);

  function showReport(id:string){ setSelectedId(id); setCardOpen(preferences.auto_open_card); setDetailId(id); setPanel("map"); }
  function openDetail(id:string){ setSelectedId(id); setCardOpen(preferences.auto_open_card); setDetailId(id); }
  function applyPreferences(next:Preferences){setPreferences(next);setTimeDays(next.default_days);if(next.start_view==="world"){setZoom(2);setCenter({lat:20,lon:0});}else if(next.start_view==="my_area")locateMe();else resetMap();}
  async function savePreferences(next:Preferences){setPreferences(next);setPreferencesStatus("Saving…");try{const data=await request("/api/profile",{method:"PATCH",headers:{Authorization:`Bearer ${token}`,"Content-Type":"application/json"},body:JSON.stringify({preferences:next})});applyPreferences(data.preferences);setPreferencesStatus("Saved");setTimeout(()=>setPreferencesStatus(""),1200);}catch(e){setPreferencesStatus(e instanceof Error?e.message:"Could not save preferences");}}
  function changeZoom(amount:number){ setZoom(current=>Math.min(15,Math.max(2,current+amount))); }
  function mapPointerDown(event:ReactPointerEvent<HTMLDivElement>){if(pointers.current.size===0)mapGesture.current=false;const reportTarget=(event.target as HTMLElement).closest<HTMLElement>("[data-report-id]");pendingReportTap.current=reportTarget?{id:reportTarget.dataset.reportId!,x:event.clientX,y:event.clientY,pointerId:event.pointerId}:null;setCardOpen(false);event.currentTarget.setPointerCapture(event.pointerId);pointers.current.set(event.pointerId,{x:event.clientX,y:event.clientY});if(pointers.current.size===1){const p=project(center.lat,center.lon,zoom);drag.current={pointerX:event.clientX,pointerY:event.clientY,centerX:p.x,centerY:p.y};pinch.current=null;}else if(pointers.current.size===2){mapGesture.current=true;pendingReportTap.current=null;const [a,b]=[...pointers.current.values()];const midX=(a.x+b.x)/2,midY=(a.y+b.y)/2;const p=project(center.lat,center.lon,zoom);pinch.current={distance:Math.hypot(a.x-b.x,a.y-b.y),zoom,worldX:p.x+midX-viewport.width/2,worldY:p.y+midY-viewport.height/2};drag.current=null;}}
  function mapPointerMove(event:ReactPointerEvent<HTMLDivElement>){if(!pointers.current.has(event.pointerId))return;if(drag.current&&Math.hypot(event.clientX-drag.current.pointerX,event.clientY-drag.current.pointerY)>5)mapGesture.current=true;pointers.current.set(event.pointerId,{x:event.clientX,y:event.clientY});if(pointers.current.size===2&&pinch.current){mapGesture.current=true;const [a,b]=[...pointers.current.values()];const distance=Math.max(10,Math.hypot(a.x-b.x,a.y-b.y));const next=Math.min(15,Math.max(2,pinch.current.zoom+Math.log2(distance/pinch.current.distance)));const ratio=2**(next-pinch.current.zoom);const midX=(a.x+b.x)/2,midY=(a.y+b.y)/2;setZoom(next);setCenter(unproject(pinch.current.worldX*ratio-(midX-viewport.width/2),pinch.current.worldY*ratio-(midY-viewport.height/2),next));}else if(drag.current){setCenter(unproject(drag.current.centerX-(event.clientX-drag.current.pointerX),drag.current.centerY-(event.clientY-drag.current.pointerY),zoom));}}
  function mapPointerEnd(event:ReactPointerEvent<HTMLDivElement>){const tap=pendingReportTap.current;const shouldOpen=!!tap&&tap.pointerId===event.pointerId&&!mapGesture.current&&pointers.current.size===1&&Math.hypot(event.clientX-tap.x,event.clientY-tap.y)<8;pointers.current.delete(event.pointerId);pendingReportTap.current=null;pinch.current=null;drag.current=null;if(shouldOpen)openDetail(tap.id);if(pointers.current.size===1){const [remaining]=[...pointers.current.values()];const p=project(center.lat,center.lon,zoom);drag.current={pointerX:remaining.x,pointerY:remaining.y,centerX:p.x,centerY:p.y};}}
  function resetMap(){ setZoom(4); setCenter({lat:39.5,lon:-98.35}); }
  function locateMe(){navigator.geolocation?.getCurrentPosition(pos=>{setCenter({lat:pos.coords.latitude,lon:pos.coords.longitude});setZoom(8);});}
  function markerPosition(r:MapReport){const point=project(r.zone_latitude,r.zone_longitude,zoom);let dx=point.x-mapGeometry.centerPx.x;if(dx>mapGeometry.size/2)dx-=mapGeometry.size;if(dx<-mapGeometry.size/2)dx+=mapGeometry.size;return{left:dx+viewport.width/2,top:point.y-mapGeometry.centerPx.y+viewport.height/2};}
  function toggleSaved(id:string){if(!token){setAuthOpen(true);return;}setSavedIds(current=>{ const next=current.includes(id)?current.filter(x=>x!==id):[...current,id]; localStorage.setItem("flyway_saved",JSON.stringify(next)); return next; }); }
  async function authenticate(){if(authBusy)return;setAuthBusy(true);setAuthError("");try{const data=await request(`/api/auth/${authMode}`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({email,password,display_name:displayName})});if(!data.access_token){setAuthError("Check your email to confirm your account, then sign in.");setAuthMode("login");return}localStorage.setItem("flyway_session",JSON.stringify(data));setToken(data.access_token);const p=await request("/api/profile",{headers:{Authorization:`Bearer ${data.access_token}`}});setProfile(p);applyPreferences(p.preferences||defaultPreferences);setAuthOpen(false)}catch(e){setAuthError(e instanceof Error?e.message:"Sign in failed")}finally{setAuthBusy(false)}}
  async function recover(){if(authBusy)return;setAuthBusy(true);setAuthError("Sending a secure recovery link…");try{const data=await request("/api/auth/recover",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({email})});setAuthError(data.message)}catch{setAuthError("If an account exists, a recovery link will be sent.")}finally{setAuthBusy(false)}}
  async function changePassword(){setSecurityStatus("Updating…");try{const data=await request("/api/auth/password",{method:"POST",headers:{Authorization:`Bearer ${token}`,"Content-Type":"application/json"},body:JSON.stringify({password:newPassword})});setNewPassword("");setSecurityStatus(data.message)}catch(e){setSecurityStatus(e instanceof Error?e.message:"Password update failed")}}
  async function openSecurity(){setSecurityOpen(true);setSecurityStatus("");try{setMfa(await request("/api/auth/mfa",{headers:{Authorization:`Bearer ${token}`}}))}catch(e){setSecurityStatus(e instanceof Error?e.message:"Security settings unavailable")}}
  async function openProfile(){setProfileDraft({...profile});setProfileOpen(true);setSecurityStatus("");try{const data=await request("/api/account/sessions",{headers:{Authorization:`Bearer ${token}`}});setSessions(data.sessions||[])}catch{setSessions([])}}
  async function saveProfile(){setSecurityStatus("Saving profile…");try{await request("/api/profile",{method:"PATCH",headers:{Authorization:`Bearer ${token}`,"Content-Type":"application/json"},body:JSON.stringify(profileDraft)});const p=await request("/api/profile",{headers:{Authorization:`Bearer ${token}`}});setProfile(p);setProfileDraft(p);setSecurityStatus("Profile saved")}catch(e){setSecurityStatus(e instanceof Error?e.message:"Could not save profile")}}
  async function signoutAll(){if(!confirm("Sign out every device, including this one?"))return;await request("/api/account/signout-all",{method:"POST",headers:{Authorization:`Bearer ${token}`}});localStorage.removeItem("flyway_session");location.href="/"}
  async function openNotifications(){setNotificationsOpen(true);const data=await request("/api/notifications",{headers:{Authorization:`Bearer ${token}`}});setNotifications(data.notifications||[])}
  async function reportContent(content_type:string,content_id:string){if(!token){setAuthOpen(true);return}const reason=prompt("Why are you reporting this content?","other");if(!reason)return;await request("/api/flags",{method:"POST",headers:{Authorization:`Bearer ${token}`,"Content-Type":"application/json"},body:JSON.stringify({content_type,content_id,reason})});setCommentStatus("Submitted for moderator review.")}
  async function enrollMfa(){setSecurityStatus("Creating authenticator enrollment…");try{const data=await request("/api/auth/mfa/enroll",{method:"POST",headers:{Authorization:`Bearer ${token}`}});setMfaEnroll({...data,totp:{...data.totp,qr_code:qrSource(data.totp?.qr_code)}});setSecurityStatus("Scan the QR code, then enter the six-digit code.")}catch(e){setSecurityStatus(e instanceof Error?e.message:"Enrollment failed")}}
  async function verifyMfa(){if(!mfaEnroll?.id)return;setSecurityStatus("Verifying…");try{const challenge=await request(`/api/auth/mfa/${mfaEnroll.id}/challenge`,{method:"POST",headers:{Authorization:`Bearer ${token}`}});await request(`/api/auth/mfa/${mfaEnroll.id}/verify`,{method:"POST",headers:{Authorization:`Bearer ${token}`,"Content-Type":"application/json"},body:JSON.stringify({challenge_id:challenge.id,code:mfaCode})});setMfaEnroll(null);setMfaCode("");setSecurityStatus("Authenticator app enabled.");setMfa(await request("/api/auth/mfa",{headers:{Authorization:`Bearer ${token}`}}))}catch(e){setSecurityStatus(e instanceof Error?e.message:"Verification failed")}}
  function openReport(){ if(!token){setAuthOpen(true);return;} setReporting(true); }
  async function submit(){ setStatus("Getting protected location…"); navigator.geolocation.getCurrentPosition(async pos=>{ try{ setStatus("Sharing activity and weather context…"); const created=await request("/api/sightings",{method:"POST",headers:{Authorization:`Bearer ${token}`,"Content-Type":"application/json"},body:JSON.stringify({species,flock_size:amountValues[amount],behavior,notes,observed_weather:observedWeather,latitude:pos.coords.latitude,longitude:pos.coords.longitude,accuracy_meters:Math.round(pos.coords.accuracy)})}); if(photo){setStatus("Compressing and sanitizing photo…");const safe=await compressImage(photo);await request(`/api/sightings/${created.id}/photos`,{method:"POST",headers:{Authorization:`Bearer ${token}`,"Content-Type":safe.type},body:safe});} setStatus("Activity shared. Your exact location stays private.");setNotes("");setPhoto(null);setObservedWeather({sky:"",precipitation:"none",wind:"",wind_direction:"",temperature:"",temperature_unit:"F",visibility:""});await load(); setTimeout(()=>{setReporting(false);setStatus("");},1400); }catch(e){setStatus(e instanceof Error?e.message:"Could not share report");} },()=>setStatus("Location permission is required to report activity."),{enableHighAccuracy:true,timeout:12000}); }
  async function postComment(){if(!token){setAuthOpen(true);return;}if(!detail||!comment.trim())return;setCommentStatus("Posting…");try{await request(`/api/sightings/${detail.id}/comments`,{method:"POST",headers:{Authorization:`Bearer ${token}`,"Content-Type":"application/json"},body:JSON.stringify({body:comment})});setComment("");const data=await request(`/api/sightings/${detail.id}/comments`);setComments(data.comments||[]);setCommentStatus("");}catch(e){setCommentStatus(e instanceof Error?e.message:"Could not post comment");}}
  async function confirm(){if(!token){setAuthOpen(true);return}if(!selected||confirmationState.confirmed||confirmationState.own_report||confirmationState.loading)return;setConfirmationState(s=>({...s,loading:true,error:undefined}));try{await request(`/api/sightings/${selected.id}/confirm`,{method:"POST",headers:{Authorization:`Bearer ${token}`}});setConfirmationState({confirmed:true,own_report:false,loading:false});setReports(rows=>rows.map(r=>r.id===selected.id?{...r,confirmations:Number(r.confirmations||0)+1}:r))}catch(e){setConfirmationState(s=>({...s,loading:false,error:e instanceof Error?e.message:"Confirmation failed"}))}}
  async function logout(){ try{await request("/api/auth/logout",{method:"POST",headers:{Authorization:`Bearer ${token}`}});}catch{} localStorage.removeItem("flyway_session");setToken("");setProfile(null);setPanel("map"); }

  const reportList=(items:MapReport[],empty:string)=><div className="activity-list">{items.length?items.map(r=><button className="activity-row" key={r.id} onClick={()=>showReport(r.id)}><span className={`duck-badge ${r.color}`}>⌁</span><span><b>{displayLabel(r.species)}</b><small>{r.flock_size} birds · {labels[r.behavior]}</small></span><span className="row-meta">{r.age}<small>{r.confidence}% confidence</small></span></button>):<div className="panel-empty">{empty}</div>}</div>;
  const openAdmin=()=>{location.href="/admin"};const renderAdmin=()=>null;

  return <main className="app-shell"><section className="map" aria-label="Duck activity map">
    <header className="topbar"><div className="brand"><div className="brandmark">F</div><div><strong>FLYWAY</strong><span>MIGRATORY ACTIVITY, NOT HUNTING SPOTS</span></div></div><button className="area" onClick={resetMap}><span><small>LIVE WORLD MAP</small>{zoom<=3?"Worldwide duck activity":zoom<=5?"United States activity":`${Math.abs(center.lat).toFixed(1)}°${center.lat>=0?"N":"S"}, ${Math.abs(center.lon).toFixed(1)}°${center.lon>=0?"E":"W"}`}</span></button><div className="weather"><span>◎</span><div><b>Global</b><small>Pan anywhere · Live reports</small></div></div><button className="avatar" onClick={()=>profile?setPanel("more"):setAuthOpen(true)} aria-label={profile?"Open account":"Sign in"}>{profile?.display_name?.slice(0,2).toUpperCase()||"IN"}</button></header>
    {panel==="map"&&<><aside className="filters">{[{slug:"all",display_name:"All birds"},...categories].map(value=><button key={value.slug} className={`filter ${filter===value.slug?"active":""}`} onClick={()=>setFilter(value.slug)}>{value.display_name}</button>)}<select className="time-filter" value={timeDays} onChange={e=>setTimeDays(Number(e.target.value))} aria-label="Sighting age"><option value={1}>Past 24 hours</option><option value={7}>Past 7 days</option><option value={30}>Past 30 days</option><option value={90}>Past 90 days</option></select></aside>
    <div ref={mapRef} className="map-canvas" onPointerDown={mapPointerDown} onPointerMove={mapPointerMove} onPointerUp={mapPointerEnd} onPointerCancel={mapPointerEnd}>
      <div className="tile-layer">{mapGeometry.tiles.map(tile=><img key={tile.key} src={tile.url} alt="" draggable={false} style={{left:tile.left,top:tile.top,width:tile.tileSize,height:tile.tileSize}}/>)}</div>
      {showFlyways&&<div className="flyway-layer" aria-label="Approximate North American flyway regions"><span className="flyway pacific">Pacific</span><span className="flyway central">Central</span><span className="flyway mississippi">Mississippi</span><span className="flyway atlantic">Atlantic</span></div>}
      {zoom<=5&&<div className="heat-layer" aria-label="Aggregated bird activity heatmap">{heatCells.map((cell,i)=>{const point=markerPosition({zone_latitude:cell.cell_latitude,zone_longitude:cell.cell_longitude} as MapReport);return <span key={i} className={`heat-cell heat-${cell.dominant_category}`} style={{left:point.left,top:point.top,opacity:Math.max(.25,cell.intensity)}} title={`${cell.report_count} protected reports`}/>})}</div>}
      {zoom>5&&zoom<=7&&clusters.map((cluster,i)=><button key={i} data-report-id={cluster.reports[0].id} className="map-cluster" style={{left:cluster.x,top:cluster.y}} onClick={e=>{if(e.detail===0)openDetail(cluster.reports[0].id)}} aria-label={`${cluster.reports.length} protected bird reports. Open details.`}><b>{cluster.reports.length}</b><span>reports</span></button>)}
      {zoom>7&&visibleReports.map(r=>{const point=markerPosition(r);return <button aria-label={`Open ${displayLabel(r.species)} report, ${r.flock_size} birds`} key={r.id} data-report-id={r.id} onClick={e=>{if(e.detail===0)openDetail(r.id)}} className={`hotspot ${r.color} ${selected?.id===r.id?"selected":""}`} style={{left:point.left,top:point.top,width:r.size,height:r.size}}><span>{r.flock_size}</span></button>})}
      {!loading&&!visibleReports.length&&<div className="empty-map"><b>No fresh sightings here</b><span>Try another filter or share protected activity.</span></div>}
    </div>
    <div className="map-controls" aria-label="Map controls"><button onClick={()=>changeZoom(.75)} aria-label="Zoom in">+</button><button onClick={()=>changeZoom(-.75)} aria-label="Zoom out">−</button><button className="reset-map" onClick={locateMe} aria-label="Go to my location">⌖</button><button className="world-map" onClick={()=>{setZoom(2);setCenter({lat:20,lon:0})}} aria-label="Show world">◎</button><button onClick={()=>setLayersOpen(true)} aria-label="Map layers">▧</button><span>ZOOM {zoom.toFixed(1)}</span></div><div className="map-attribution">© OpenStreetMap contributors</div>
    {cardOpen&&selected&&visibleReports.some(r=>r.id===selected.id)&&<section className="report-card"><button className="close-card" onClick={()=>setCardOpen(false)} aria-label="Dismiss live activity">×</button><div className="report-head"><div className={`duck-badge ${selected.color}`}>⌁</div><div><span className="eyebrow">LIVE ACTIVITY · {selected.age.toUpperCase()} AGO</span><h2>{displayLabel(selected.species)}</h2></div><button className={`save-btn ${savedIds.includes(selected.id)?"saved":""}`} onClick={()=>toggleSaved(selected.id)} aria-label={savedIds.includes(selected.id)?"Remove saved sighting":"Save sighting"}>{savedIds.includes(selected.id)?"★":"☆"}</button><div className="confidence"><b>{selected.confidence}%</b><span>CONFIDENCE</span></div></div><div className="stats"><div><span>ESTIMATED FLOCK</span><strong>{selected.flock_size} birds</strong></div><div><span>BEHAVIOR</span><strong>{labels[selected.behavior]}</strong></div><div><span>CONFIRMED</span><strong className="up">{selected.confirmations} hunters</strong></div></div><div className="privacy"><span><b>Location protected</b>This report is displayed as a randomized activity zone. The hunter’s exact spot is never returned.</span></div><div className="confirm"><span>Seen them too?</span><button className="confirm-btn" onClick={confirm}>✓ Confirm activity</button></div></section>}</>}
    {panel!=="map"&&<div className="panel-backdrop" onClick={()=>setPanel("map")}><section className="content-panel" onClick={e=>e.stopPropagation()}><div className="panel-head"><div><span className="eyebrow">FLYWAY NETWORK</span><h2>{panel==="activity"?"Recent activity":panel==="saved"?"Saved sightings":panel==="admin"?"Administration":"Your account"}</h2></div><div className="panel-actions">{panel==="activity"&&<button onClick={load}>↻ Refresh</button>}<button className="panel-close" onClick={()=>setPanel("map")} aria-label="Close and return to map">×</button></div></div>{panel==="activity"&&reportList(reports,"No recent reports yet.")}{panel==="saved"&&reportList(savedReports,"Save useful sightings from the map and they’ll appear here on this device.")}{panel==="admin"&&renderAdmin()}{panel==="more"&&<div className="account-card"><div className="account-avatar">{profile?.display_name?.slice(0,2).toUpperCase()||"IN"}</div><h3>{profile?.display_name||"Hunter"}</h3><p>Preferences follow your account across devices. Exact report coordinates always remain protected.</p><div className="preferences-form"><div className="preference-block"><span>BIRD VISIBILITY</span><small>Choose which groups appear on your map.</small><div className="preference-toggles">{categories.map(group=><button key={group.slug} className={preferences.visible_groups.includes(group.slug)?"active":""} onClick={()=>savePreferences({...preferences,visible_groups:preferences.visible_groups.includes(group.slug)?preferences.visible_groups.filter(g=>g!==group.slug):[...preferences.visible_groups,group.slug]})}><b>{preferences.visible_groups.includes(group.slug)?"✓":""}</b>{group.display_name}</button>)}</div></div><label className="preference-row"><span><b>Default history</b><small>Initial age range for sightings</small></span><select value={preferences.default_days} onChange={e=>savePreferences({...preferences,default_days:Number(e.target.value)})}><option value={1}>24 hours</option><option value={7}>7 days</option><option value={30}>30 days</option><option value={90}>90 days</option></select></label><label className="preference-row"><span><b>Starting map</b><small>View used after sign-in</small></span><select value={preferences.start_view} onChange={e=>savePreferences({...preferences,start_view:e.target.value as Preferences["start_view"]})}><option value="us">United States</option><option value="world">World</option><option value="my_area">My area</option></select></label><label className="preference-row"><span><b>Open activity card</b><small>Show the summary after selecting a marker</small></span><input type="checkbox" checked={preferences.auto_open_card} onChange={e=>savePreferences({...preferences,auto_open_card:e.target.checked})}/></label>{preferencesStatus&&<div className="preference-status">{preferencesStatus}</div>}</div>{profile?.role&&profile.role!=="user"&&<button className="admin-button" onClick={openAdmin}>Open admin console</button>}<button className="signout-button" onClick={logout}>Sign out</button></div>}</section></div>}
    <nav className="bottom-nav"><button className={panel==="map"?"active":""} onClick={()=>setPanel("map")}><span className="icon">⌖</span>Map</button><button className={panel==="activity"?"active":""} onClick={()=>setPanel("activity")}><span className="icon">≡</span>Activity</button><button className="report-button" onClick={openReport}><span>＋</span>Report birds</button><button className={panel==="saved"?"active":""} onClick={()=>token?setPanel("saved"):setAuthOpen(true)}><span className="icon">☆</span>Saved</button><button className={panel==="more"?"active":""} onClick={()=>profile?setPanel("more"):setAuthOpen(true)}><span className="icon">◌</span>{profile?"Account":"Sign in"}</button></nav>
  </section>
  {detail&&<aside className="detail-context-tools"><div><span>REPORTED BY</span><b>{detail.reporter_name||"Flyway member"}</b></div>{detail.observed_weather&&<div><span>REPORTED CONDITIONS</span><b>{[detail.observed_weather.sky?.replaceAll("_"," "),detail.observed_weather.precipitation,detail.observed_weather.wind&&`${detail.observed_weather.wind} wind`].filter(Boolean).join(" · ")}</b><small>{detail.observed_weather.temperature!==undefined?`${detail.observed_weather.temperature}°${detail.observed_weather.temperature_unit||"F"}`:""}{detail.observed_weather.wind_direction?` · ${detail.observed_weather.wind_direction}`:""}{detail.observed_weather.visibility?` · ${detail.observed_weather.visibility} visibility`:""}</small></div>}{detail.weather&&<div><span>REGIONAL WEATHER SNAPSHOT</span><b>{detail.weather.temperature}° · {detail.weather.wind_speed} {detail.weather.wind_unit}</b><small>{detail.weather.cloud_cover}% cloud · {detail.weather.pressure_msl} hPa</small></div>}{token&&<div className="content-report-tools"><button onClick={()=>reportContent("sighting",detail.id)}>Report sighting</button>{detail.notes&&<button onClick={()=>reportContent("note",detail.id)}>Report note</button>}{photos.map(photo=><button key={photo.id} onClick={()=>reportContent("photo",photo.id)}>Report photo</button>)}{comments.map(item=><button key={item.id} onClick={()=>reportContent("comment",item.id)}>Report comment</button>)}</div>}</aside>}
  {panel==="more"&&profile&&<div className="account-quick-actions"><button onClick={openProfile}>Edit profile</button><button onClick={openNotifications}>Notifications</button><button onClick={openSecurity}>Password &amp; security</button>{profile.role!=="user"&&<a href="/admin">Administration</a>}<button onClick={logout}>Sign out</button></div>}
  {detail&&<div className="modal-wrap" onClick={()=>setDetailId("")}><article className="modal detail-modal" onClick={e=>e.stopPropagation()}><div className="modal-head"><div><span className="eyebrow">PROTECTED ACTIVITY ZONE · {detail.age.toUpperCase()} AGO</span><h2>{displayLabel(detail.species)}</h2></div><button onClick={()=>setDetailId("")} aria-label="Close details">×</button></div><div className="detail-hero"><div className={`duck-badge ${detail.color}`}>⌁</div><div><b>{detail.flock_size} birds</b><span>{labels[detail.behavior]}</span></div><div className="detail-confidence"><b>{detail.confidence}%</b><span>confidence</span></div></div><div className="detail-grid"><div><span>REPORTED</span><b>{new Date(detail.occurred_at).toLocaleString()}</b></div><div><span>COMMUNITY</span><b>{detail.confirmations} confirmations</b></div><div><span>LOCATION</span><b>Randomized activity zone</b></div><div><span>SPECIES GROUP</span><b>{categories.find(item=>item.slug===categoryFor(detail.species))?.display_name||"Migratory bird"}</b></div></div><section className="sighting-story">{detail.notes&&<div className="report-note"><span>REPORTER NOTE</span><p>{detail.notes}</p></div>}{photos.length>0&&<div className="photo-grid">{photos.map(item=><img key={item.id} src={`${API}${item.url}`} alt={`Photo attached to ${displayLabel(detail.species)} sighting`}/>)}</div>}</section><div className="shield"><span>◉</span><div><b>Exact location hidden</b><p>The map displays a randomized zone. The reporting hunter’s exact coordinates, route, and blind are never shown.</p></div></div><section className="comments"><div className="comments-head"><b>Community comments</b><span>{comments.length}</span></div>{comments.length?<div className="comment-list">{comments.map(item=><article key={item.id}><b>{item.display_name}</b><time>{new Date(item.created_at).toLocaleString()}</time><p>{item.body}</p></article>)}</div>:<p className="no-comments">No comments yet.</p>}<div className="comment-compose"><textarea value={comment} onChange={e=>setComment(e.target.value)} maxLength={500} placeholder={token?"Add a helpful observation…":"Sign in to comment"} disabled={!token}/><button onClick={postComment}>{token?"Post":"Sign in"}</button></div>{commentStatus&&<p className="comment-status">{commentStatus}</p>}</section><div className="detail-actions"><button className={`save-detail ${savedIds.includes(detail.id)?"saved":""}`} onClick={()=>toggleSaved(detail.id)}>{savedIds.includes(detail.id)?"★ Saved":"☆ Save sighting"}</button><button className="confirm-btn" onClick={confirm}>✓ Confirm activity</button></div></article></div>}
  {reporting&&<div className="modal-wrap" onClick={()=>setReporting(false)}><div className="modal" onClick={e=>e.stopPropagation()}><div className="modal-head"><div><span className="eyebrow">COMMUNITY SIGHTING</span><h2>Report migratory bird activity</h2></div><button onClick={()=>setReporting(false)}>×</button></div><div className="shield"><span>◉</span><div><b>Your location will be blurred</b><p>Hunters receive a randomized activity zone—not your pin, route, or blind.</p></div></div><label>What did you see?</label><div className="choice-grid">{catalog.map(item=><button className={species===item.slug?"active":""} onClick={()=>setSpecies(item.slug)} key={item.slug}>{item.display_name}</button>)}</div><label>How many?</label><div className="choice-grid four">{Object.keys(amountValues).map(a=><button className={amount===a?"active":""} onClick={()=>setAmount(a)} key={a}>{a}</button>)}</div><label>What were they doing?</label><select value={behavior} onChange={e=>setBehavior(e.target.value)}><option value="feeding">Feeding</option><option value="circling">Circling</option><option value="flying_over">Flying over</option><option value="resting">Resting on water</option><option value="moving_in">Moving into area</option></select><fieldset className="weather-report"><legend>Observed weather (optional)</legend><div className="weather-report-grid"><label>Sky<select value={observedWeather.sky} onChange={e=>setObservedWeather({...observedWeather,sky:e.target.value})}><option value="">Not specified</option><option value="clear">Clear</option><option value="partly_cloudy">Partly cloudy</option><option value="overcast">Overcast</option><option value="fog">Fog</option></select></label><label>Precipitation<select value={observedWeather.precipitation} onChange={e=>setObservedWeather({...observedWeather,precipitation:e.target.value})}><option value="none">None</option><option value="drizzle">Drizzle</option><option value="rain">Rain</option><option value="snow">Snow</option><option value="sleet">Sleet</option></select></label><label>Wind<select value={observedWeather.wind} onChange={e=>setObservedWeather({...observedWeather,wind:e.target.value})}><option value="">Not specified</option><option value="calm">Calm</option><option value="light">Light</option><option value="moderate">Moderate</option><option value="strong">Strong</option></select></label><label>Direction<select value={observedWeather.wind_direction} onChange={e=>setObservedWeather({...observedWeather,wind_direction:e.target.value})}><option value="">Not specified</option>{["N","NE","E","SE","S","SW","W","NW"].map(v=><option key={v}>{v}</option>)}</select></label><label>Temperature<span className="temperature-entry"><input type="number" min="-100" max="150" value={observedWeather.temperature} onChange={e=>setObservedWeather({...observedWeather,temperature:e.target.value})}/><select value={observedWeather.temperature_unit} onChange={e=>setObservedWeather({...observedWeather,temperature_unit:e.target.value})}><option>F</option><option>C</option></select></span></label><label>Visibility<select value={observedWeather.visibility} onChange={e=>setObservedWeather({...observedWeather,visibility:e.target.value})}><option value="">Not specified</option><option value="good">Good</option><option value="moderate">Moderate</option><option value="poor">Poor</option></select></label></div></fieldset><label>Field note (optional)</label><textarea value={notes} onChange={e=>setNotes(e.target.value)} maxLength={1000} placeholder="Habitat, direction of travel, or other useful context…"/><label>Photo (optional)</label><input className="photo-input" type="file" accept="image/jpeg,image/png,image/webp" onChange={e=>{const file=e.target.files?.[0]||null;if(file&&file.size>5242880){setStatus("Photo must be 5 MB or smaller.");setPhoto(null);}else setPhoto(file);}}/><button className="share" onClick={submit}>Share protected report →</button>{status&&<p className="form-status">{status}</p>}</div></div>}
  {authOpen&&<div className="modal-wrap" onClick={()=>setAuthOpen(false)}><form className="modal auth-modal" onClick={e=>e.stopPropagation()} onSubmit={e=>{e.preventDefault();authMode==="recover"?recover():authenticate()}}><div className="modal-head"><div><span className="eyebrow">HUNTER ACCOUNT</span><h2>{authMode==="login"?"Welcome back":authMode==="signup"?"Join Flyway":"Reset your password"}</h2></div><button type="button" onClick={()=>setAuthOpen(false)}>×</button></div>{authMode==="signup"&&<><label>Display name</label><input autoComplete="name" value={displayName} onChange={e=>setDisplayName(e.target.value)} placeholder="Marsh Hunter"/></>}<label>Email</label><input type="email" autoComplete="email" required value={email} onChange={e=>setEmail(e.target.value)} placeholder="hunter@example.com"/>{authMode!=="recover"&&<><label>Password</label><input type="password" autoComplete={authMode==="login"?"current-password":"new-password"} required value={password} onChange={e=>setPassword(e.target.value)} placeholder="8 characters minimum"/></>}<button type="submit" className="share" disabled={authBusy}>{authBusy?"Please wait…":authMode==="login"?"Sign in":authMode==="signup"?"Create account":"Send recovery link"}</button>{authError&&<p className="form-status">{authError}</p>}{authMode==="login"&&<button type="button" className="auth-switch" onClick={()=>setAuthMode("recover")}>Forgot password?</button>}<button type="button" className="auth-switch" onClick={()=>setAuthMode(authMode==="login"?"signup":"login")}>{authMode==="login"?"New to Flyway? Create an account":"Return to sign in"}</button></form></div>}
  {securityOpen&&<div className="modal-wrap" onClick={()=>setSecurityOpen(false)}><div className="modal auth-modal" onClick={e=>e.stopPropagation()}><div className="modal-head"><div><span className="eyebrow">ACCOUNT SECURITY</span><h2>Password &amp; MFA</h2></div><button onClick={()=>setSecurityOpen(false)} aria-label="Close security">×</button></div><label>New password</label><input type="password" value={newPassword} onChange={e=>setNewPassword(e.target.value)} placeholder="12+ characters with letters and numbers"/><button className="share" onClick={changePassword}>Change password</button><div className="security-summary"><b>Authenticator app (TOTP)</b><p>{mfa?.factors?.length?`${mfa.factors.length} factor enrolled`:"Optional for your account."}</p><small>Current policy: {mfa?.policy?.mfa_policy||"optional"}. Administrator TOTP is configurable and currently optional.</small>{!mfaEnroll&&<button className="auth-switch" onClick={enrollMfa}>Set up authenticator</button>}{mfaEnroll&&<div className="mfa-enroll">{mfaEnroll.totp?.qr_code&&<img src={mfaEnroll.totp.qr_code} alt="Authenticator setup QR code"/>}<code>{mfaEnroll.totp?.secret}</code><input inputMode="numeric" maxLength={6} value={mfaCode} onChange={e=>setMfaCode(e.target.value.replace(/\D/g,""))} placeholder="6-digit code"/><button className="share" onClick={verifyMfa}>Verify authenticator</button></div>}</div>{securityStatus&&<p className="form-status">{securityStatus}</p>}</div></div>}
  {profileOpen&&<div className="modal-wrap" onClick={()=>setProfileOpen(false)}><div className="modal account-edit-modal" onClick={e=>e.stopPropagation()}><div className="modal-head"><div><span className="eyebrow">PUBLIC PROFILE</span><h2>Edit profile</h2></div><button onClick={()=>setProfileOpen(false)}>×</button></div><div className="profile-grid"><label>First name<input value={profileDraft.first_name||""} onChange={e=>setProfileDraft({...profileDraft,first_name:e.target.value})}/></label><label>Last name<input value={profileDraft.last_name||""} onChange={e=>setProfileDraft({...profileDraft,last_name:e.target.value})}/></label><label>Broad region<input value={profileDraft.region||""} onChange={e=>setProfileDraft({...profileDraft,region:e.target.value})} placeholder="State, province, or country"/></label><label>Distance units<select value={profileDraft.distance_units||"miles"} onChange={e=>setProfileDraft({...profileDraft,distance_units:e.target.value})}><option value="miles">Miles</option><option value="kilometers">Kilometers</option></select></label></div><label>Short bio<textarea maxLength={280} value={profileDraft.bio||""} onChange={e=>setProfileDraft({...profileDraft,bio:e.target.value})}/></label><label className="profile-toggle"><span><b>Show my name on community activity</b><small>{profileDraft.show_attribution!==false?`${profileDraft.first_name||"First name"}${profileDraft.last_name?` ${profileDraft.last_name[0].toUpperCase()}.`:""}`:"Flyway member"}</small></span><input type="checkbox" checked={profileDraft.show_attribution===true} onChange={e=>setProfileDraft({...profileDraft,show_attribution:e.target.checked})}/></label><button className="share" onClick={saveProfile}>Save profile</button><section className="session-list"><h3>Active sessions</h3>{sessions.map(s=><div key={s.id}><span><b>{s.current?"Current session":"Signed-in device"}</b><small>{s.device} · {new Date(s.last_seen_at).toLocaleString()}</small></span></div>)}<button className="danger-action" onClick={signoutAll}>Sign out everywhere</button></section>{securityStatus&&<p className="form-status">{securityStatus}</p>}</div></div>}
  {notificationsOpen&&<div className="modal-wrap" onClick={()=>setNotificationsOpen(false)}><div className="modal notifications-modal" onClick={e=>e.stopPropagation()}><div className="modal-head"><div><span className="eyebrow">YOUR ACTIVITY</span><h2>Notifications</h2></div><button onClick={()=>setNotificationsOpen(false)}>×</button></div><div className="notification-list">{notifications.length?notifications.map(n=><a key={n.id} href={n.href||"#"}><b>{n.title}</b><p>{n.body}</p><time>{new Date(n.created_at).toLocaleString()}</time></a>):<p>No notifications yet.</p>}</div></div></div>}
  {layersOpen&&<div className="modal-wrap" onClick={()=>setLayersOpen(false)}><div className="modal layers-modal" onClick={e=>e.stopPropagation()}><div className="modal-head"><div><span className="eyebrow">MAP CONTEXT</span><h2>Map layers</h2></div><button onClick={()=>setLayersOpen(false)}>×</button></div><label className="profile-toggle"><span><b>North American flyways</b><small>Approximate planning regions, not precise biological boundaries.</small></span><input type="checkbox" checked={showFlyways} onChange={e=>setShowFlyways(e.target.checked)}/></label><div className="layer-future"><b>Future layers</b><span>Weather · Wetlands · Refuges · Public lands · Conservation areas</span></div><div className="legal-notice"><b>Hunting regulations</b><p>Season dates, shooting hours, bag limits, permits, and legal access vary by jurisdiction and change annually. Flyway activity is informational only. Always verify current federal, state, tribal, refuge, local, and property-specific rules with the responsible wildlife agency.</p><a href="https://www.fws.gov/law/migratory-bird-hunting-regulations" target="_blank" rel="noreferrer">U.S. Fish &amp; Wildlife Service regulations</a></div></div></div>}
  </main>;
}
